-- 004_n5_words_inari_part2
-- N5 單字補匯：伏見稻荷大社 part 2（CSV 行 102-343，共 242 字）
-- 資料源：stephenmk/yomitan-jlpt-vocab (CC-BY, Jonathan Waller / Tanos)
-- 中文翻譯：Claude（學生友善口語風格）

with new_words as (
  returning id, lemma
)
select
  (select id from shrines where slug = 'inari'),
  nw.id,
  100 + row_number() over (order by nw.lemma)
from new_words nw;
